SELECT AVG(route_count) AS avg_routes_per_app
FROM (
    SELECT app_id, COUNT(route_id) AS route_count
    FROM application_routes
    GROUP BY app_id
) AS app_route_counts;

SELECT applications.app_name, organizations.organization_name
FROM applications
JOIN organizations ON applications.organization_id = organizations.organization_id;

SELECT apps.app_name, orgs.organization_name
FROM applications AS apps
LEFT JOIN organizations AS orgs ON apps.organization_id = orgs.organization_id;

SELECT organization_id
FROM applications
WHERE app_id = 'YOUR_APP_ID';
